{
  "name": "Medicare Savings Programs",
  "eligibility": {
    "age": null,
    "income_limits": "Mississippi's Medicare Savings Programs (MSPs) have three tiers with specific monthly income limits for individuals and couples (married). No limits for larger households specified; spousal impoverishment rules apply for long-term care scenarios where only the applicant's income is counted if one spouse applies. Current 2026 limits (most states, including MS): QMB (100% FPL + $20): $1,350 individual, $1,824 couple; SLMB (120% FPL + $20): $1,616 individual, $2,184 couple; QI (135% FPL + $20): $1,816 individual, $2,455 couple. Older MS-specific data: QMB $1,325/$1,783; SLMB up to $1,585/$2,135; QI up to $1,781/$2,400 (individual/couple). All require Medicare Part A eligibility. Income disregards: first $20/month, $65 wages + half remaining wages.[1][2][3]",
    "asset_limits": "No resource/asset test for any MSP tier in Mississippi (QMB, SLMB, QI). Federal baselines ($9,950 individual/$14,910 couple) do not apply here; resources do not matter.[2]",
    "other_requirements": ["Must be eligible for Medicare Part A (Hospital Insurance).", "Mississippi resident.", "U.S. citizen or qualified non-citizen."]
  },
  "benefits": {
    "type": "financial",
    "value": "QMB: Pays Medicare Part A/B premiums (including Part A if owed), deductibles, coinsurance/copayments. SLMB: Pays Part B premiums only (up to 3 months retroactive). QI: Pays Part B premiums only. QMB recipients get a Medicaid card; SLMB/QI do not qualify for additional Medicaid benefits.[1][2]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: https://medicaid.ms.gov (apply for Medicaid/Medicare cost-sharing)", "Phone: Contact Mississippi Division of Medicaid at 1-800-421-2408 or local office", "Mail/In-person: Local Mississippi Department of Human Services (DHS) Medicaid office (find via medicaid.ms.gov)", "Through State Health Insurance Assistance Program (SHIP): www.shiphelp.org"],
    "processing_time": "QMB: Begins one month after approval (no retroactive). SLMB: Month qualified, up to 3 months before application month. QI: Varies, federal funding capped.[2]",
    "waitlist": "QI may have waitlist or funding caps as Congress appropriates limited funds annually; not guaranteed.[2][9]",
    "forms": ["Medicaid Application (no specific MSP form number listed; apply via general Medicaid app for cost-sharing)", "Form for Medicare Cost-Sharing via MS Division of Medicaid"],
    "documents": ["Proof of Medicare enrollment (Part A/B)", "Income proof (pay stubs, SSI/SSDI awards, bank statements)", "Proof of residency", "ID (birth certificate, Social Security card)", "Marital status proof if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered uniformly statewide by MS Division of Medicaid, but apply via local DHS offices which may have slight processing differences; no specified provider or wait time variations.[2]",
    "offices_or_providers": ["Local Mississippi DHS Medicaid offices statewide (locations at medicaid.ms.gov)"]
  },
  "official_source": "https://medicaid.ms.gov/medicaid-coverage/who-qualifies-for-coverage/medicare-cost-sharing/",
  "gotchas": ["No asset test in MS (unlike many states), but income limits are strict and tiered—check exact tier as benefits differ significantly.", "QI has federal funding caps, leading to waitlists or denials even if income-eligible.", "QMB has no retroactive coverage; SLMB does (up to 3 months).", "Spousal impoverishment only for LTSS, not standard MSP.", "Income limits updated annually based on FPL; 2026 figures apply but verify current via official site.", "SLMB/QI do not provide Medicaid card or extra benefits beyond Part B premium.", "Even if over federal limits, MS may disregard certain income/assets—always apply.[2][3][5]"],
  "data_shape_notes": "No asset test (unique to MS among many states); tiered by income with different benefits and retroactivity; income only for individual/couple (no full household table); QI funding capped federally; spousal rules differ for LTSS."
}

{
  "name": "Mississippi State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; prioritizes people with limited incomes but open to all Medicare beneficiaries, their families, and caregivers[1][5]",
    "asset_limits": "No asset limits or tests apply[1]",
    "other_requirements": ["Must be a Medicare beneficiary, under age 65 with Medicare due to disability, dually eligible for Medicare and Medicaid, or family/caregiver of such individuals[1][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling (in-person or phone), education, assistance with Medicare options (Parts A/B/C/D, Medigap), applications for Medicare Savings Programs, Extra Help/LIS, Medicaid; help with claims, appeals, fraud prevention via SMP, policy comparisons, paperwork organization, referrals; group presentations and outreach[1][3][5]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-844-822-4622 (M-F 8am-5pm) or 601-709-0624[5][8]", "Website: Mississippi Department of Human Services (mdhs.ms.gov) Finding Services for Older Adults page[5]", "In-person: Through MDHS Division of Aging and Adult Services or local network providers (contact via phone for appointment)[2][5]"],
    "processing_time": "No formal processing; services provided via appointment scheduling upon contact[3][5]",
    "waitlist": null,
    "forms": ["No specific application form; contact for counseling appointment[3]"],
    "documents": ["Medicare card, current health insurance details, prescription drug list, income/asset info if applying for Savings Programs/Extra Help (counselors assist with this)[3][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide to Mississippi Medicare beneficiaries[2]",
    "regional_variations": "Delivered via statewide network with local affiliates (e.g., Area Agencies on Aging) for region-specific advice on plans/providers, but core services uniform[7]",
    "offices_or_providers": ["Administered by Mississippi Department of Human Services (MDHS), Division of Aging and Adult Services, 750 North State Street, Jackson MS 39202[2][5]"]
  },
  "official_source": "https://www.mdhs.ms.gov/post/navigating-medicare-made-easy-with-ship/[5]",
  "gotchas": ["Not a financial aid or healthcare provider program—only counseling/education, no direct payments or medical services; prioritizes but doesn't restrict to low-income; during Open Enrollment (e.g., Oct 15-Dec 7), high demand may affect appointment availability; counselors help with but don't guarantee approval for Savings Programs[1][3][5]"],
  "data_shape_notes": "no income/asset test, open to all Medicare-related inquiries, counseling-only service via statewide phone/in-person network with local customization[1][5][7]"
}

{
  "name": "Home Delivered Meals (Meals on Wheels)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits or means testing; program is not income-based[1][2].",
    "asset_limits": "No asset limits or means testing[1].",
    "other_requirements": ["Homebound or unable to prepare meals due to age, disability, or health status[1][2]", "Reside in a service delivery area/zone[1][2]", "Priority to those on no congregate meals waiting list; may extend to others if no waitlist[1]", "60+ years old or disabled/homebound (varies slightly by local provider)[2][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Minimum of 33 1/3% of dietary reference intakes (DRIs) per meal; one meal per delivery, nutritionally balanced per Older Americans Act standards; may include emergency/shelf-stable meals[1]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging for your region (no statewide phone; find via local search)[2]", "In-person or phone assessment with local provider (e.g., Union Nutrition Site for specific areas)[2][7]"],
    "processing_time": "Varies; some within a week, longer if waitlist[2]",
    "waitlist": "Yes, home-delivered waiting list takes priority; access limited if waitlist exists[1]",
    "forms": ["No specific statewide form named; initial assessment questions on age, health, mobility, dietary needs[2]"],
    "documents": ["Proof of age, residence, medical information (e.g., conditions, dietary restrictions), emergency contacts; financial docs sometimes but not always required since no means test[2]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Limited to delivery zones/service areas of local providers; must verify local coverage[1][2]",
    "regional_variations": "Administered by local Area Agencies on Aging and providers (e.g., Union Nutrition Site); different geographic coverage, wait times, and exact eligibility nuances by region/county[1][2][7]",
    "offices_or_providers": ["Local Area Agency on Aging (contact for specific county)", "Examples: Union Nutrition Site (age 60+)[7]"]
  },
  "official_source": "https://www.law.cornell.edu/regulations/mississippi/18-Miss-Code-R-SS-2-2-10 (Mississippi Code R. 2-2.10)[1]",
  "gotchas": ["Not means-tested but strictly homebound-focused; car ownership or ability to leave home/cook may disqualify[2]", "Must live in delivery zone; out-of-area seniors need alternatives[2]", "Priority waitlists block access even if eligible[1]", "Separate from Medicaid HCBS waivers (Elderly & Disabled, etc.) which may offer additional meals but require enrollment[3]", "Voluntary contributions requested but not mandatory[1]"],
  "data_shape_notes": "Decentralized by local Area Agencies on Aging with no statewide application; no income/asset test but homebound and zone-restricted; priority via waitlist system[1][2]"
}

{
