    "asset_limits": "No asset limits mentioned in available sources.",
    "other_requirements": ["Reside in service area (central/southern Mississippi for MCLSC: 43 counties; northern for NMRLS).", "Priority for special groups like seniors, though no strict age cutoff.", "Must have civil legal issue in areas like elder care, housing, family, consumer, etc."]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal assistance (no attorney fees), including advice, representation in areas like elder care, family, housing, employment, consumer, income maintenance, health, domestic violence, foreclosure prevention; provided by nonprofit law firms for low-income persons.[1][3][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: MCLSC (central/southern MS) 1-800-519-2915 or 1-800-498-1804; NMRLS (northern MS) 1-800-898-8731.", "Online intake: Temporarily closed for NMRLS; apply via MCLSC site at mscenterforlegalservices.org.", "In-person/mail: Contact intake hotlines for local offices in 43-county areas."],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["No specific form names/numbers listed; intake via phone or online application process."],
    "documents": ["Proof of income (e.g., pay stubs, benefit statements), household composition details; prepare current total household receipts data."]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Divided by region: North Mississippi (NMRLS), Central/Southern Mississippi (MCLSC, 43 counties).",
    "regional_variations": "Separate providers (NMRLS vs. MCLSC) with distinct intake lines as of Jan 1, 2026; NMRLS emphasizes elder care; online intake closed for NMRLS.[3][7]",
    "offices_or_providers": ["North Mississippi Rural Legal Services (NMRLS): nmrls.com.", "Mississippi Center for Legal Services (MCLSC): mscenterforlegalservices.org, 43 counties central/southern."]
  },
  "official_source": "https://www.mslegalservices.org (guide); https://mscenterforlegalservices.org; https://www.nmrls.com",
